module sr_latch (
    input s,
    input r,
    output reg invalid_q,
    output reg q_bar
);

    always @ (*) begin
        if (s && !r) begin
            invalid_q <= 1;
            q_bar <= 0;
        end else if (!s && r) begin
            invalid_q <= 0;
            q_bar <= 1;
        end
    end

endmodule
